// Parse RSS XML, filter to posts from the last 2 days only
const xml = $input.first().json.body || String($input.first().json);
const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;
while ((match = itemRegex.exec(xml)) !== null) {
  const item = match[1];
  const title = (item.match(/<title>(?:<![CDATA[)?([\s\S]*?)(?:]]>)?<\/title>/) || [])[1] || '';
  const link = (item.match(/<link>([\s\S]*?)<\/link>/) || [])[1] || '';
  const pubDate = (item.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || [])[1] || '';
  items.push({ title: title.trim(), link: link.trim(), pubDate: pubDate.trim() });
}

// Filter to last 2 days
const cutoff = new Date(Date.now() - 2 * 86400000);
const recent = items.filter(i => {
  const d = new Date(i.pubDate);
  return !isNaN(d) && d >= cutoff;
});

if (recent.length === 0) {
  return [{ json: { skipped: true, reason: 'No new posts in last 2 days' } }];
}

return recent.map(i => ({ json: i }));

// Extract article text from Substack page HTML
const html = $input.first().json.body || String($input.first().json);
const title = $input.first().json.title || 'Untitled';
const link = $input.first().json.link || '';
const pubDate = $input.first().json.pubDate || '';

// Try to extract from _preloads JSON first (full content)
let text = '';
const preloadMatch = html.match(/window\._preloads\s*=\s*JSON\.parse\("(.*?)"\)/);
if (preloadMatch) {
  try {
    const raw = preloadMatch[1].replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)));
    const data = JSON.parse(raw);
    const bodyHtml = data?.post?.body_html || '';
    text = bodyHtml.replace(/<[^>]+>/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/\s+/g, ' ').trim();
  } catch (e) {
    // Fall through to meta extraction
  }
}

// Fallback: extract from meta tags / visible text
if (!text || text.length < 100) {
  // Try og:description
  const ogMatch = html.match(/<meta[^>]*property="og:description"[^>]*content="([^"]*)"/);
  if (ogMatch) {
    text = ogMatch[1].replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
  }
  // Also grab any visible paragraphs
  const paras = html.match(/<p[^>]*>([\s\S]*?)<\/p>/g);
  if (paras && text.length < 500) {
    const paraText = paras.map(p => p.replace(/<[^>]+>/g, '').trim()).filter(p => p.length > 20).join(' ');
    text = text ? text + ' ' + paraText : paraText;
  }
}

if (!text || text.length < 50) {
  return [{ json: { skipped: true, reason: 'Could not extract content', link } }];
}

const content = `Substack: ${title}\nDate: ${pubDate ? new Date(pubDate).toISOString().slice(0, 10) : 'unknown'}\n\n${text.slice(0, 8000)}`;

return [{ json: {
  content,
  title: title.slice(0, 300),
  link,
  pubDate,
  source_type: 'substack',
  metadata: JSON.stringify({
    source: 'substack-daily',
    title: title.slice(0, 300),
    url: link,
    date: pubDate ? new Date(pubDate).toISOString().slice(0, 10) : 'unknown'
  })
}}];

